import{_ as a,o,c as i,ag as t}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"O Dotfiles | Dotfiles (PL)","titleTemplate":":title","description":"Odkryj przeglad techniczny Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","frontmatter":{"title":"O Dotfiles | Dotfiles","description":"Odkryj przeglad techniczny Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","lang":"pl-PL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"O Dotfiles | Dotfiles preview","canonical":"/pl/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"O Dotfiles","pageType":"docs","schemaType":"WebPage","permalink":"/pl/about/"},"headers":[],"relativePath":"pl/about/index.md","filePath":"pl/about/index.md","lastUpdated":1773010926000}'),l={name:"pl/about/index.md"};function d(c,e,s,n,r,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="o-dotfiles" tabindex="-1">O Dotfiles <a class="header-anchor" href="#o-dotfiles" aria-label="Permalink to &quot;O Dotfiles&quot;">​</a></h1><p>Dotfiles v0.2.495 to wieloplatformowa konfiguracja powloki zarzadzana przez Chezmoi.</p><h2 id="instalacja" tabindex="-1">Instalacja <a class="header-anchor" href="#instalacja" aria-label="Permalink to &quot;Instalacja&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="weryfikacja" tabindex="-1">Weryfikacja <a class="header-anchor" href="#weryfikacja" aria-label="Permalink to &quot;Weryfikacja&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="polecenia-glowne" tabindex="-1">Polecenia glowne <a class="header-anchor" href="#polecenia-glowne" aria-label="Permalink to &quot;Polecenia glowne&quot;">​</a></h2><ul><li><code>dot apply</code> stosuje zmiany konfiguracji.</li><li><code>dot update</code> aktualizuje repozytorium i odswieza pamiec podreczna.</li><li><code>dot doctor</code> weryfikuje sciezki, narzedzia i stan powloki.</li><li><code>dot heal</code> naprawia brakujacy lub uszkodzony stan.</li><li><code>dot smoke-test</code> waliduje glowne lancuchy narzedzi.</li></ul><h2 id="powiazane" tabindex="-1">Powiazane <a class="header-anchor" href="#powiazane" aria-label="Permalink to &quot;Powiazane&quot;">​</a></h2><ul><li><a href="/pl/aliases/">Aliasy</a></li><li><a href="/pl/functions/">Funkcje</a></li><li><a href="/pl/paths/">Sciezki</a></li></ul><h2 id="polecenia-głowne" tabindex="-1">Polecenia główne <a class="header-anchor" href="#polecenia-głowne" aria-label="Permalink to &quot;Polecenia główne&quot;">​</a></h2><p>CLI <code>dot</code> udostępnia 53 polecenia zorganizowane według kategorii.</p><h3 id="rdzen" tabindex="-1">Rdzeń <a class="header-anchor" href="#rdzen" aria-label="Permalink to &quot;Rdzeń&quot;">​</a></h3><ul><li><code>dot apply</code> — stosuje zmiany konfiguracji.</li><li><code>dot sync</code> — pobiera najnowszy stan repozytorium i stosuje.</li><li><code>dot update</code> — aktualizuje repozytorium i rozgrzewa pamięci podręczne.</li><li><code>dot add</code> — dodaje nowe pliki do źródła Chezmoi.</li><li><code>dot diff</code> — wyświetla oczekujące zmiany przed zastosowaniem.</li><li><code>dot status</code> — wyświetla status zarządzanych plików.</li><li><code>dot remove</code> — usuwa plik z zarządzania i kasuje wpis źródłowy.</li><li><code>dot cd</code> — otwiera powłokę w katalogu źródłowym Chezmoi.</li><li><code>dot edit</code> — otwiera zarządzany plik w edytorze.</li><li><code>dot clean-cache</code> — czyści tymczasowe pamięci podręczne.</li><li><code>dot prewarm</code> — wstępnie wypełnia pamięci podręczne dla szybszego startu powłoki.</li></ul><h3 id="diagnostyka" tabindex="-1">Diagnostyka <a class="header-anchor" href="#diagnostyka" aria-label="Permalink to &quot;Diagnostyka&quot;">​</a></h3><ul><li><code>dot doctor</code> — weryfikuje ścieżki, narzędzia i stan powłoki.</li><li><code>dot heal</code> — automatycznie naprawia brakujący lub uszkodzony stan.</li><li><code>dot health</code> — uruchamia lekkie sprawdzenie stanu.</li><li><code>dot verify</code> — sprawdza integralność plików względem źródła.</li><li><code>dot scorecard</code> — wyświetla ocenę jakości konfiguracji.</li><li><code>dot snapshot</code> — przechwytuje bieżący stan do późniejszego porównania.</li><li><code>dot smoke-test</code> — w pełni weryfikuje podstawowe łańcuchy narzędzi.</li><li><code>dot chaos</code> — wstrzykuje błędy w celu testowania samonaprawy.</li><li><code>dot bundle</code> — eksportuje przenośny pakiet konfiguracji.</li><li><code>dot rollback</code> — cofa do poprzedniego snapshota.</li><li><code>dot drift</code> — wykrywa nieautoryzowane zmiany w zarządzanych plikach.</li><li><code>dot history</code> — wyświetla dziennik historii apply/sync.</li><li><code>dot benchmark</code> — mierzy czas uruchamiania powłoki.</li><li><code>dot perf</code> — profiluje wolną inicjalizację powłoki.</li></ul><h3 id="wyglad" tabindex="-1">Wygląd <a class="header-anchor" href="#wyglad" aria-label="Permalink to &quot;Wygląd&quot;">​</a></h3><ul><li><code>dot theme</code> — przełącza schemat kolorów terminala.</li><li><code>dot wallpaper</code> — ustawia tapetę pulpitu (macOS).</li><li><code>dot fonts</code> — instaluje lub aktualizuje Nerd Fonts.</li><li><code>dot tune</code> — dostosowuje gęstość interfejsu i styl znaku zachęty.</li></ul><h3 id="bezpieczenstwo" tabindex="-1">Bezpieczeństwo <a class="header-anchor" href="#bezpieczenstwo" aria-label="Permalink to &quot;Bezpieczeństwo&quot;">​</a></h3><ul><li><code>dot backup</code> — tworzy zaszyfrowane kopie zapasowe konfiguracji.</li><li><code>dot encrypt-check</code> — weryfikuje szyfrowanie sekretów w stanie spoczynku.</li><li><code>dot firewall</code> — konfiguruje reguły zapory ogniowej hosta.</li><li><code>dot telemetry</code> — kontroluje anonimową telemetrię użycia.</li><li><code>dot dns-doh</code> — włącza DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — natychmiast blokuje ekran.</li><li><code>dot usb-safety</code> — ogranicza automatyczne montowanie pamięci masowej USB.</li></ul><h3 id="sekrety" tabindex="-1">Sekrety <a class="header-anchor" href="#sekrety" aria-label="Permalink to &quot;Sekrety&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — inicjalizuje backend sekretów (age / GPG).</li><li><code>dot secrets</code> — wyświetla zaszyfrowane wpisy sekretów.</li><li><code>dot secrets-create</code> — tworzy nowy zaszyfrowany sekret.</li><li><code>dot ssh-key</code> — generuje lub rotuje pary kluczy SSH.</li><li><code>dot ssh-cert</code> — żąda certyfikatu SSH od CA.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — otwiera interaktywną sesję asystenta AI.</li><li><code>dot ai-setup</code> — konfiguruje klucze API dla dostawców AI.</li><li><code>dot ai-query</code> — wysyła jednorazowe zapytanie do modelu AI.</li><li>Wrappery narzędzi AI: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="narzedzia" tabindex="-1">Narzędzia <a class="header-anchor" href="#narzedzia" aria-label="Permalink to &quot;Narzędzia&quot;">​</a></h3><ul><li><code>dot tools</code> — wyświetla dołączone zamienniki CLI i ich status.</li><li><code>dot new</code> — tworzy nowy plik aliasu lub funkcji.</li><li><code>dot sandbox</code> — otwiera jednorazową powłokę sandbox.</li><li><code>dot keys</code> — wyświetla aktualne skróty klawiszowe.</li><li><code>dot learn</code> — uruchamia interaktywny samouczek.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — aktualizuje Dotfiles do najnowszej wersji.</li><li><code>dot packages</code> — wyświetla zainstalowane pakiety zarządzane przez Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — wyświetla informacje o wersji lub użyciu</li></ul>',28)])])}const z=a(l,[["render",d]]);export{h as __pageData,z as default};
